1	// Glues CsrTrigger and StateDrain. The simulator's run-loop calls on_retire
2	// once per committed PC; the controller decides via the trigger map whether
3	// to drain state and returns the populated hybrid_state_v1 if so. The
4	// caller (simulator.hpp) is responsible for writing the file and exiting
5	// with EXIT_HANDOFF_TO_QEMU.
6	
7	#pragma once
8	
9	#include "hybrid/csr_trigger.hpp"
10	#include "hybrid/insn_match.h"
11	#include "hybrid/resume_driver.hpp"
12	#include "hybrid/state_abi.h"
13	#include "hybrid/state_drain.hpp"
14	
15	#include <cstdint>
16	#include <optional>
17	#include <utility>
18	
19	namespace hybrid
20	{
21	
22	class HandoffController
23	{
24	public:
25	  HandoffController(CsrTrigger trigger, DmiBus& bus)
26	      : trigger_{std::move(trigger)}, drain_{bus}
27	  {}
28	
29	  template<typename GprProbe>
30	  auto on_retire(uint64_t pc, GprProbe&& read_gpr)
31	    -> std::optional<hybrid_state_v1>
32	  {
33	    const auto hit = trigger_.lookup(pc);
34	    if (!hit) return std::nullopt;
35	
36	    bool fire = false;
37	    switch (hit->kind) {
38	    case HYBRID_HANDOFF_EXIT:
39	      fire = true;
40	      break;
41	    case HYBRID_HANDOFF_RUNTIME: {
42	      const auto rs1 = decode_csrrw_rs1(hit->insn);
43	      fire = (read_gpr(rs1) == 1u);
44	      break;
45	    }
46	    case HYBRID_HANDOFF_ENTER:  // entry is QEMU's job; vsim ignores it
47	    case HYBRID_HANDOFF_NONE:
48	      break;
49	    }
50	    if (!fire) return std::nullopt;
51	    return drain_.drain();
52	  }
53	
54	private:
55	  CsrTrigger trigger_;
56	  StateDrain drain_;
57	};
58	
59	}  // namespace hybrid
