1	// StateDrain is the dual of ResumeDriver: halt the hart via the Debug Module,
2	// read x1..x31 + DPC via Abstract Commands, populate hybrid_state_v1.
3	//
4	// Reuses ResumeDriver's DM register constants and DmiBus interface. Vector
5	// regs, FPRs, and CSRs beyond DPC are deferred to Phase 5.
6	
7	#pragma once
8	
9	#include "hybrid/abstract_command.hpp"
10	#include "hybrid/dmi_poll.hpp"
11	#include "hybrid/resume_driver.hpp"
12	#include "hybrid/state_abi.h"
13	
14	#include <cstdint>
15	
16	namespace hybrid
17	{
18	
19	class StateDrain
20	{
21	public:
22	  using RD = ResumeDriver;
23	
24	  explicit StateDrain(DmiBus& bus)
25	      : bus_{bus}
26	  {}
27	
28	  auto drain() -> hybrid_state_v1
29	  {
30	    bus_.write(RD::kDmcontrol, RD::kDmcontrolDmactive);
31	    bus_.write(RD::kDmcontrol, RD::kDmcontrolDmactive | RD::kDmcontrolHaltreq);
32	    poll_until_set(bus_, RD::kDmstatus, RD::kDmstatusAllhalted,
33	                   "StateDrain halt");
34	
35	    hybrid_state_v1 state{};
36	    state.magic   = HYBRID_STATE_MAGIC;
37	    state.version = HYBRID_STATE_VERSION;
38	    state.flags   = HYBRID_FLAG_RV64;
39	    state.priv    = 3;
40	
41	    for (uint16_t i = 1; i < 32; ++i)
42	      state.gpr[i] = read_64bit_register(regno_gpr(i));
43	
44	    state.pc = read_64bit_register(regno_csr(RD::kCsrDpc));
45	    return state;
46	  }
47	
48	private:
49	  auto read_64bit_register(uint16_t regno) -> uint64_t
50	  {
51	    bus_.write(RD::kCommand, access_register_command(regno, AarSize::Bits64,
52	                                                     /*write=*/false));
53	    poll_until_clear(bus_, RD::kAbstractcs, RD::kAbstractcsBusy,
54	                     "StateDrain read_register");
55	    const uint64_t lo = bus_.read(RD::kData0);
56	    const uint64_t hi = bus_.read(RD::kData1);
57	    return lo | (hi << 32);
58	  }
59	
60	  DmiBus& bus_;
61	};
