1	// Pattern recogniser for the magic handoff CSR convention. The same predicate
2	// runs in two places: the QEMU TCG plugin (C) and the vsim PC pre-scan (C++).
3	
4	#ifndef HYBRID_INSN_MATCH_H
5	#define HYBRID_INSN_MATCH_H
6	
7	#include <stdbool.h>
8	#include <stdint.h>
9	
10	#ifdef __cplusplus
11	extern "C" {
12	#endif
13	
14	typedef enum
15	{
16	  HYBRID_HANDOFF_NONE    = 0,
17	  HYBRID_HANDOFF_ENTER   = 1,  // csrwi 0x7C0, 0
18	  HYBRID_HANDOFF_EXIT    = 2,  // csrwi 0x7C0, 1
19	  HYBRID_HANDOFF_RUNTIME = 3,  // csrw  0x7C0, rs1 (kind read at run time)
20	} hybrid_handoff_kind;
21	
22	#define HYBRID_TRIGGER_CSR 0x7C0u
23	
24	// Returns true when `insn` is a SYSTEM-opcode write with rd=0 to CSR 0x7C0.
25	// On match, *out_kind is set to ENTER, EXIT, or RUNTIME.
26	static inline bool hybrid_match_handoff_insn(uint32_t insn,
27	                                             hybrid_handoff_kind* out_kind)
28	{
29	  if ((insn & 0x7Fu) != 0x73u) return false;          // SYSTEM opcode
30	  if (((insn >> 7) & 0x1Fu) != 0u) return false;      // rd = x0
31	  if (((insn >> 20) & 0xFFFu) != HYBRID_TRIGGER_CSR) return false;
32	
33	  const uint32_t funct3 = (insn >> 12) & 0x7u;
34	  if (funct3 == 0b001u) {
35	    *out_kind = HYBRID_HANDOFF_RUNTIME;
36	    return true;
37	  }
38	  if (funct3 == 0b101u) {
39	    const uint32_t uimm = (insn >> 15) & 0x1Fu;
40	    if (uimm == 0u) {
41	      *out_kind = HYBRID_HANDOFF_ENTER;
42	      return true;
43	    }
44	    if (uimm == 1u) {
45	      *out_kind = HYBRID_HANDOFF_EXIT;
46	      return true;
47	    }
48	    return false;
49	  }
50	  return false;
51	}
52	
53	#ifdef __cplusplus
54	}  // extern "C"
55	#endif
56	
57	#endif  // HYBRID_INSN_MATCH_H
