19	class ResumeDriver
20	{
21	public:
22	  static constexpr uint8_t kData0      = 0x04;
23	  static constexpr uint8_t kData1      = 0x05;
24	  static constexpr uint8_t kDmcontrol  = 0x10;
25	  static constexpr uint8_t kDmstatus   = 0x11;
26	  static constexpr uint8_t kAbstractcs = 0x16;
27	  static constexpr uint8_t kCommand    = 0x17;
28	
29	  static constexpr uint16_t kCsrDpc = 0x7B1;
30	
31	  static constexpr uint32_t kDmcontrolDmactive  = 1u << 0;
32	  static constexpr uint32_t kDmcontrolResumereq = 1u << 30;
33	  static constexpr uint32_t kDmcontrolHaltreq   = 1u << 31;
34	
35	  static constexpr uint32_t kDmstatusAllhalted    = 1u << 9;
36	  static constexpr uint32_t kDmstatusAllresumeack = 1u << 17;
37	
38	  static constexpr uint32_t kAbstractcsBusy = 1u << 12;
39	
40	  static constexpr unsigned kPollIterations = kDmiPollIterations;
41	
42	  explicit ResumeDriver(DmiBus& bus)
43	      : bus_{bus}
44	  {}
45	
46	  void resume(const hybrid_state_v1& state)
47	  {
48	    if (state.magic != HYBRID_STATE_MAGIC)
49	      throw std::runtime_error("ResumeDriver::resume: bad magic");
50	    if (state.version != HYBRID_STATE_VERSION)
51	      throw std::runtime_error("ResumeDriver::resume: unsupported version");
52	
53	    // dmactive must transition 0->1 in its own write before any other
54	    // DMCONTROL bit is honored (RISC-V Debug Spec).
55	    bus_.write(kDmcontrol, kDmcontrolDmactive);
56	    request_halt();
57	    poll_until_set(bus_, kDmstatus, kDmstatusAllhalted, "ResumeDriver halt");
58	
59	    // x0 is hard-wired zero; skip it.
60	    for (uint16_t i = 1; i < 32; ++i)
61	      write_64bit_register(regno_gpr(i), state.gpr[i]);
62	
63	    write_64bit_register(regno_csr(kCsrDpc), state.pc);
64	
65	    request_resume();
66	    poll_until_set(bus_, kDmstatus, kDmstatusAllresumeack,
67	                   "ResumeDriver resume");
68	  }
69	
70	private:
71	  void request_halt()
72	  {
73	    bus_.write(kDmcontrol, kDmcontrolDmactive | kDmcontrolHaltreq);
74	  }
75	
76	  void request_resume()
77	  {
78	    bus_.write(kDmcontrol, kDmcontrolDmactive | kDmcontrolResumereq);
79	  }
80	
81	  void write_64bit_register(uint16_t regno, uint64_t value)
82	  {
83	    bus_.write(kData0, uint32_t(value & 0xffffffffu));
84	    bus_.write(kData1, uint32_t((value >> 32) & 0xffffffffu));
85	    bus_.write(kCommand,
86	               access_register_command(regno, AarSize::Bits64, /*write=*/true));
87	    poll_until_clear(bus_, kAbstractcs, kAbstractcsBusy,
88	                     "ResumeDriver write_register");
89	  }
90	
91	  DmiBus& bus_;
92	};
